const startedAt = new Date().toISOString();
const missingVars = [];
if (!$env.TELEGRAM_BOT_TOKEN) missingVars.push('TELEGRAM_BOT_TOKEN');
if (!$env.TELEGRAM_CHAT_ID) missingVars.push('TELEGRAM_CHAT_ID');
if (!$env.DASHBOARD_API_KEY) missingVars.push('DASHBOARD_API_KEY');
if (missingVars.length > 0) {
  throw new Error('Pre-hook FAIL: ' + missingVars.join(', '));
}
const out = { startedAt, contextOk: true, workflow: 'weekly-lead-report-v2' };
return [{ json: out }];

const ctx = $('Pre-Hook: Valida Contesto').first().json;
const snap = $('Get Snapshot').first().json;
const endedAt = new Date().toISOString();
const durationMs = new Date(endedAt) - new Date(ctx.startedAt);

const auto = snap.automation || {};
const stats = auto.stats || {};
const weekly = stats.weekly || {};
const total = stats.total || {};

const invitesSent = weekly.invitesSent ?? stats.invitesSent ?? 'n/d';
const invitesAccepted = weekly.invitesAccepted ?? stats.accepted ?? 'n/d';
const messagesSent = weekly.messagesSent ?? stats.messagesSent ?? 'n/d';
const replies = weekly.replies ?? stats.replies ?? 'n/d';
const pendingRatio = auto.pendingRatio ?? 'n/d';
const riskAction = auto.riskAction || 'UNKNOWN';
const healthScore = auto.healthScore ?? 'n/d';

const now = new Date();
const weekStr = now.toLocaleDateString('it-IT', { day: '2-digit', month: '2-digit', year: 'numeric' });

const acceptanceRate = (typeof invitesSent === 'number' && invitesSent > 0 && typeof invitesAccepted === 'number')
  ? ((invitesAccepted / invitesSent) * 100).toFixed(1) + '%'
  : 'n/d';

const replyRate = (typeof messagesSent === 'number' && messagesSent > 0 && typeof replies === 'number')
  ? ((replies / messagesSent) * 100).toFixed(1) + '%'
  : 'n/d';

const report = [
  '📊 *Weekly Lead Report — ' + weekStr + '*',
  '',
  '*Inviti*',
  '  Inviati: ' + invitesSent,
  '  Accettati: ' + invitesAccepted + ' (' + acceptanceRate + ')',
  '',
  '*Messaggi*',
  '  Inviati: ' + messagesSent,
  '  Risposte: ' + replies + ' (' + replyRate + ')',
  '',
  '*Stato account*',
  '  Pending ratio: ' + (typeof pendingRatio === 'number' ? (pendingRatio * 100).toFixed(1) + '%' : pendingRatio),
  '  Risk: ' + riskAction,
  '  Health score: ' + healthScore,
  '',
  '_Durata report: ' + durationMs + 'ms_'
].join('
');

const out = { report, invitesSent, invitesAccepted, messagesSent, replies, riskAction, startedAt: ctx.startedAt, endedAt, durationMs };
return [{ json: out }];

const r = $input.first().json;
const log = {
  workflow: 'weekly-lead-report-v2',
  invitesSent: r.invitesSent,
  messagesSent: r.messagesSent,
  riskAction: r.riskAction,
  durationMs: r.durationMs,
  loggedAt: new Date().toISOString()
};
console.log('[POST-HOOK weekly-report]', JSON.stringify(log));
return [{ json: log }];
